mapper.select:
SELECT id, order_no, user_id, session_id, total_amount, status, pay_time, expire_time, create_time, update_time
FROM `order`
WHERE id = #{id}

SELECT id, order_no, user_id, session_id, total_amount, status, pay_time, expire_time, create_time, update_time
FROM `order`
WHERE order_no = #{orderNo}

mapper.update:
UPDATE `order`
SET status = #{toStatus}, update_time = NOW()
WHERE id = #{id} AND status = #{fromStatus}

mapper.select:
SELECT id, order_no, user_id, session_id, total_amount, status, pay_time, expire_time, create_time, update_time
FROM `order`
WHERE status = #{status}
  AND expire_time < #{expireTime}
LIMIT #{limit}

mapper.update:
UPDATE `order`
SET status   = #{status},
    pay_time = #{payTime}
WHERE id = #{id}

mapper.select:
SELECT id, order_no, user_id, session_id, total_amount, status, pay_time, expire_time, create_time, update_time
FROM `order`
WHERE user_id = #{userId}
AND status = #{status}
AND create_time >= #{startTime}
AND create_time <= #{endTime}
ORDER BY create_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM `order`
WHERE user_id = #{userId}
AND status = #{status}
AND create_time >= #{startTime}
AND create_time <= #{endTime}
